if (Quasars.getFlagShowQuasars()) {
    core.debug("Quasars are visible");
}

if (Quasars.getFlagUseQuasarMarkers()) {
    core.debug("Quasars shown with markers");
} else {
    core.debug("Quasars shown as distribution points");
}

// Use marker icons for quasars
Quasars.setFlagUseQuasarMarkers(true);

// Use simple distribution points
Quasars.setFlagUseQuasarMarkers(false);

if (Quasars.getDisplayMode()) {
    core.debug("Quasar distribution mode is enabled");
}

// Show quasar distribution density
Quasars.setDisplayMode(true);

// Show individual quasar markers
Quasars.setDisplayMode(false);

var colorStr = core.getStelProperty('Quasars.quasarsColor');
var parts = colorStr.split(',');
var r = parseFloat(parts[0]);
var g = parseFloat(parts[1]);
var b = parseFloat(parts[2]);
core.debug("Quasar color: RGB(" + r + ", " + g + ", " + b + ")");

var newColor = core.vec3f(1.0, 0.5, 0.4);
Quasars.setMarkerColor(newColor);

if (Quasars.getUpdatesEnabled()) {
    core.debug("Automatic quasar catalog updates are enabled");
}

// Enable automatic catalog updates
Quasars.setUpdatesEnabled(true);

// Disable automatic updates
Quasars.setUpdatesEnabled(false);

// Manually update quasar catalog
Quasars.updateJSON();
core.debug("Quasar catalog update started...");

// Wait for update to complete
core.wait(30);
core.debug("Quasar catalog updated");

// Update monthly
Quasars.setUpdateFrequencyDays(30);

// Update yearly
Quasars.setUpdateFrequencyDays(365);

var state = Quasars.getUpdateState();
if (state === 0) core.debug("Updating catalog...");
else if (state === 1) core.debug("No updates needed");
else if (state === 2) core.debug("Catalog updated successfully");
else if (state === 3) core.debug("Download error occurred");

if (Quasars.getEnableAtStartup()) {
    core.debug("Quasars will load on next startup");
}

// Enable Quasars on next startup
Quasars.setEnableAtStartup(true);

// Disable Quasars on next startup
Quasars.setEnableAtStartup(false);

if (Quasars.getFlagShowQuasarsButton()) {
    core.debug("Quasars toolbar button is visible");
}

// Show Quasars button on toolbar
Quasars.setFlagShowQuasarsButton(true);

// Hide Quasars button
Quasars.setFlagShowQuasarsButton(false);

// Reset all Quasars plugin settings to defaults
Quasars.restoreDefaults();
core.debug("Quasars settings restored to defaults");

var quasar = Quasars.getByID("3C 273");
if (quasar) {
    core.debug("Found 3C 273");
    core.moveToObject(quasar.getEnglishName(), 3);
}

var allQuasars = Quasars.getAllQuasars();
core.debug("Total quasars: " + allQuasars.length);

// Print first 10 quasar names
for (var i = 0; i < Math.min(10, allQuasars.length); i++) {
    core.debug(allQuasars[i].getEnglishName());
}

var quasar = Quasars.searchByID("3C 273");
if (quasar) {
    core.debug("Moving to 3C 273");
    core.moveToObject(quasar.getEnglishName(), 3);
}

var quasar = Quasars.searchByName("3C 273");
if (quasar) {
    core.debug("Found quasar at redshift: " + quasar.getRedshift());
    core.moveToObject(quasar.getEnglishName(), 3);
}
